import{_ as i,c as t,o as a,ag as n}from"./chunks/framework.GdcW6lnn.js";const k=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"basics_api/jwt.md","filePath":"basics_api/jwt.md"}'),l={name:"basics_api/jwt.md"};function e(o,s,p,r,g,h){return a(),t("div",null,s[0]||(s[0]=[n(`<h3 id="🗝️-jwt-json-web-tokens-компактнии-та-самодостатніи-спосіб-безпечноі-передачі-інформаціі" tabindex="-1">🗝️ JWT (JSON Web Tokens): Компактний та самодостатній спосіб безпечної передачі інформації <a class="header-anchor" href="#🗝️-jwt-json-web-tokens-компактнии-та-самодостатніи-спосіб-безпечноі-передачі-інформаціі" aria-label="Permalink to “🗝️ JWT (JSON Web Tokens): Компактний та самодостатній спосіб безпечної передачі інформації”">​</a></h3><p><strong>Що це?</strong></p><p>JWT (JSON Web Token) - це <strong>стандарт RFC 7519</strong>, який визначає <strong>компактний, самодостатній та безпечний спосіб передачі інформації між сторонами</strong> як об&#39;єкт JSON, підписаний цифровим підписом. Цей підпис може бути виконаний за допомогою секретного ключа (з використанням алгоритму HMAC) або пари ключів (публічний/приватний ключ з використанням RSA або ECDSA).</p><p>JWT часто використовуються для <strong>аутентифікації</strong> (хто користувач?) та <strong>авторизації</strong> (що користувач може робити?). Завдяки своїй самодостатності, вони можуть містити всю необхідну інформацію про користувача та його права доступу, що зменшує необхідність багаторазових звернень до бази даних.</p><p><strong>Структура JWT:</strong></p><p>JWT складається з трьох частин, розділених крапками (<code>.</code>):</p><ol><li><p><strong>Header (Заголовок):</strong> Містить метадані про токен, такі як тип токена (<code>alg</code>, algorithm - алгоритм підпису) та тип вмісту (<code>typ</code>, type - зазвичай &quot;JWT&quot;). Заголовок кодується в Base64Url.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;alg&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;HS256&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;typ&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;JWT&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li><li><p><strong>Payload (Корисне навантаження):</strong> Містить <strong>твердження (claims)</strong> - інформацію про сутність (зазвичай користувача) та інші дані. Існують три типи тверджень:</p><ul><li><strong>Зареєстровані (Registered Claims):</strong> Стандартні, але необов&#39;язкові твердження, такі як: <ul><li><code>iss</code> (issuer) - видавець токена.</li><li><code>sub</code> (subject) - суб&#39;єкт токена (зазвичай ID користувача).</li><li><code>aud</code> (audience) - отримувач токена.</li><li><code>exp</code> (expiration time) - час закінчення терміну дії токена (у форматі Unix timestamp).</li><li><code>nbf</code> (not before) - час, раніше якого токен не є дійсним.</li><li><code>iat</code> (issued at) - час видачі токена.</li><li><code>jti</code> (JWT ID) - унікальний ідентифікатор токена.</li></ul></li><li><strong>Публічні (Public Claims):</strong> Твердження, визначені користувачами. Їх слід обирати обережно, щоб уникнути конфліктів імен.</li><li><strong>Приватні (Private Claims):</strong> Кастомні твердження, що використовуються для передачі специфічної для програми інформації між сторонами.</li></ul><p>Корисне навантаження кодується в Base64Url.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;sub&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1234567890&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;John Doe&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;admin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;iat&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1516239022</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li><li><p><strong>Signature (Підпис):</strong> Створюється шляхом об&#39;єднання закодованих заголовка та корисного навантаження, їх підписання за допомогою алгоритму, вказаного в заголовку, та секретного ключа (для HMAC) або приватного ключа (для RSA або ECDSA). Підпис використовується для <strong>перевірки цілісності</strong> токена (чи не був він змінений після видачі) та <strong>автентичності</strong> (чи був він підписаний довіреною стороною).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Signature = HMACSHA256(base64UrlEncode(header) + &quot;.&quot; + base64UrlEncode(payload), secret)</span></span></code></pre></div><p>Підпис кодується в Base64Url.</p></li></ol><p><strong>Як це працює (спрощений сценарій аутентифікації):</strong></p><ol><li>Коли користувач успішно аутентифікується на сервері, сервер генерує JWT, що містить інформацію про користувача (наприклад, його ID) та підписує його за допомогою секретного ключа.</li><li>Сервер повертає цей JWT клієнту (зазвичай у заголовку <code>Authorization: Bearer YOUR_JWT</code> або у cookie).</li><li>Клієнт зберігає JWT та включає його в кожен наступний запит до захищених ресурсів API (зазвичай у заголовку <code>Authorization: Bearer YOUR_JWT</code>).</li><li>Сервер API отримує JWT, перевіряє його підпис за допомогою того самого секретного ключа (або відповідного публічного ключа, якщо використовується асиметричне шифрування).</li><li>Якщо підпис дійсний, сервер вважає користувача автентифікованим та може отримати інформацію про нього з корисного навантаження токена. Сервер також може перевірити твердження, такі як термін дії токена (<code>exp</code>).</li></ol><p><strong>Переваги JWT:</strong></p><ul><li><strong>Компактність:</strong> JWT є невеликими за розміром, що робить їх зручними для передачі в HTTP-заголовках або URL.</li><li><strong>Самодостатність:</strong> Токен містить всю необхідну інформацію про користувача, що зменшує необхідність звертатися до бази даних для кожного запиту (stateless).</li><li><strong>Безпека:</strong> Підпис гарантує цілісність та автентичність токена.</li><li><strong>Масштабованість:</strong> Stateless-архітектура спрощує масштабування серверної частини.</li><li><strong>Простота використання:</strong> Легко генерувати та перевіряти на різних платформах та мовах програмування завдяки існуючим бібліотекам.</li></ul><p><strong>Недоліки JWT:</strong></p><ul><li><strong>Розмір:</strong> Хоча й компактні, розмір токена може зростати зі збільшенням кількості тверджень, що може впливати на продуктивність при передачі у заголовках.</li><li><strong>Відкликання:</strong> Відкликати JWT може бути складно, оскільки вони самодостатні. Після видачі термін їх дії продовжується до закінчення. Для вирішення цієї проблеми часто використовуються короткий термін дії токенів та/або додаткові механізми відкликання (наприклад, чорні списки токенів на сервері).</li><li><strong>Секретний ключ:</strong> Безпека залежить від збереження секретного ключа (для HMAC) або приватного ключа (для асиметричного шифрування) в таємниці.</li></ul><p><strong>Використання JWT:</strong></p><ul><li><strong>Аутентифікація:</strong> Передача JWT після успішної аутентифікації користувача для подальшої ідентифікації.</li><li><strong>Авторизація:</strong> Передача інформації про права доступу користувача в корисне навантаження токена для прийняття рішень щодо авторизації на сервері.</li><li><strong>Передача інформації:</strong> Безпечна передача неконфіденційної інформації між сторонами.</li></ul><p><strong>Висновок:</strong></p><p>JWT є потужним інструментом для реалізації безпечної аутентифікації та авторизації в веб-додатках та API. Їхня самодостатність та можливість перевірки цілісності роблять їх популярним вибором для сучасних розподілених систем. Однак, важливо враховувати їхні обмеження, особливо щодо відкликання, та вживати відповідних заходів безпеки при їх використанні.</p>`,17)]))}const c=i(l,[["render",e]]);export{k as __pageData,c as default};
